"use client";
import React from "react";
import { MinusIcon, PlusIcon } from "./icons";
import { CartItem } from "@/app/page";

interface Props {
 cart: CartItem[];
 onUpdateQuantity: (id: number, delta: number) => void;
 total: number;
}

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <aside className="w-full h-full flex flex-col bg-white border-l border-border-light p-10 animate-reveal">
   <div className="flex items-baseline justify-between mb-10">
    <h2 className="text-[20px] font-heading font-black uppercase tracking-widest">Basket</h2>
    <span className="text-[12px] font-bold text-accent-gold uppercase tracking-widest">{cart.length} Products</span>
   </div>

   <div className="flex-1 space-y-8 overflow-y-auto pr-4 -mr-4 scrollbar-hide">
    {cart.length === 0 ? (
     <div className="flex flex-col items-center justify-center h-full text-center py-20 opacity-20">
      <span className="text-4xl mb-4">🥮</span>
      <p className="text-[14px] font-heading font-bold uppercase tracking-widest">Your selection is empty</p>
     </div>
    ) : (
     cart.map((item) => (
      <div key={item.id} className="group animate-reveal">
       <div className="flex gap-4 mb-4">
        <div className="w-20 h-20 bg-bg-parchment flex items-center justify-center border border-border-light">
         <div className="w-12 h-12 bg-accent-gold opacity-10 rounded-full blur-xl" />
        </div>

        <div className="flex-1 min-w-0">
         <p className="text-[13px] font-heading font-bold text-fg-main uppercase tracking-wide truncate mb-1">
          {item.name}
         </p>
         <p className="text-[11px] font-bold text-fg-muted uppercase tracking-widest mb-3">Unit Price: {item.price} ₽</p>

         <div className="flex items-center justify-between">
          <div className="flex items-center gap-4 px-3 py-1.5 border border-border-light">
           <button onClick={() => onUpdateQuantity(item.id, -1)} className="hover:text-accent-gold transition-colors">
            <MinusIcon size={12} />
           </button>
           <span className="text-[12px] font-heading font-bold w-4 text-center">{item.quantity}</span>
           <button onClick={() => onUpdateQuantity(item.id, 1)} className="hover:text-accent-gold transition-colors">
            <PlusIcon size={12} />
           </button>
          </div>
          <span className="text-[15px] font-heading font-black">{item.price * item.quantity} ₽</span>
         </div>
        </div>
       </div>
      </div>
     ))
    )}
   </div>

   <div className="mt-10 border-t border-border-light pt-10">
    <div className="flex justify-between items-baseline mb-6">
     <span className="text-[13px] font-bold text-fg-muted uppercase tracking-widest">Subtotal</span>
     <span className="text-[24px] font-heading font-black tracking-tight">{total} P</span>
    </div>

    <button
     className="btn-boutique w-full h-[60px] tracking-[0.2em] disabled:opacity-30 disabled:pointer-events-none"
     disabled={cart.length === 0}
    >
     Checkout Now
    </button>

    <p className="text-[10px] text-fg-muted font-bold text-center mt-6 uppercase tracking-widest leading-relaxed">
     Artisanal quality guaranteed. <br />Delivered fresh in 15-20 min.
    </p>
   </div>
  </aside>
 );
};

export default CartSidebar;
