"use client";

import React, { useState, useEffect } from "react";
import Header from "@/components/Header";
import PromoBanners from "@/components/PromoBanners";
import ProductCard from "@/components/ProductCard";
import CartSidebar from "@/components/CartSidebar";
import { products } from "@/components/data";

export interface CartItem {
 id: number;
 name: string;
 price: number;
 oldPrice?: number;
 quantity: number;
 accent: string;
}

const CATEGORIES = ["Heritage Breads", "Viennoiserie", "Small Batch", "Healthy Living", "Gift boxes"];

export default function Home() {
 const [cart, setCart] = useState<CartItem[]>([]);
 const [activeCategory, setActiveCategory] = useState("Heritage Breads");

 const addToCart = (product: typeof products[0]) => {
  setCart((prev) => {
   const found = prev.find((i) => i.id === product.id);
   if (found) return prev.map((i) => i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
   const accentValue = (product as any).accent || "bg-bg-parchment";
   return [...prev, { id: product.id, name: product.name, price: product.price, oldPrice: product.oldPrice, quantity: 1, accent: accentValue }];
  });
 };

 const updateQty = (id: number, delta: number) => {
  setCart((prev) =>
   prev.map((i) => i.id === id ? { ...i, quantity: Math.max(0, i.quantity + delta) } : i)
    .filter((i) => i.quantity > 0)
  );
 };

 const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);

 return (
  <div className="min-h-screen bg-bg-pure selection:bg-accent-gold-soft selection:text-fg-main">
   <Header />

   <main className="flex min-h-screen">

    {/* Gallery View (Main) */}
    <div className="flex-1 min-w-0 border-r border-border-light">

     <div className="animate-reveal">
      <PromoBanners />
     </div>

     {/* Editorial Category Strip */}
     <div className="sticky top-[80px] z-50 bg-white/90 backdrop-blur-xl px-12 py-8 border-b border-border-light">
      <div className="max-w-[1440px] mx-auto flex items-center justify-between">
       <div className="flex items-center gap-10 overflow-x-auto no-scrollbar py-2">
        {CATEGORIES.map((cat) => (
         <button
          key={cat}
          onClick={() => setActiveCategory(cat)}
          className={`text-[12px] font-bold uppercase tracking-[0.25em] whitespace-nowrap transition-all relative group ${activeCategory === cat ? "text-fg-main" : "text-fg-muted"
           }`}
         >
          {cat}
          <span className={`absolute -bottom-2 left-0 h-[2px] bg-accent-gold transition-all duration-500 ${activeCategory === cat ? "w-full" : "w-0 group-hover:w-1/2"
           }`} />
         </button>
        ))}
       </div>

       <div className="hidden lg:flex items-center gap-6">
        <span className="text-[10px] font-black uppercase tracking-[0.2em] text-fg-muted">View Style:</span>
        <div className="flex gap-2">
         <div className="w-4 h-4 border-2 border-fg-main" />
         <div className="w-4 h-4 border-2 border-border-light" />
        </div>
       </div>
      </div>
     </div>

     {/* Product Collection Grid */}
     <section className="px-12 py-20 max-w-[1600px] mx-auto">
      <div className="flex flex-col mb-16 animate-reveal">
       <h1 className="text-[48px] font-heading font-black tracking-tighter leading-none mb-4">
        THE COLLECTION
       </h1>
       <div className="flex items-center gap-4">
        <div className="h-[1px] w-20 bg-accent-gold" />
        <p className="text-[14px] text-fg-soft font-medium uppercase tracking-[0.1em]">Currently curating {products.length} artisanal goods</p>
       </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-10">
       {products.map((p) => (
        <ProductCard
         key={p.id}
         {...p}
         image={(p as any).image || ""}
         onAdd={() => addToCart(p)}
        />
       ))}

       {/* End of Collection Card */}
       <div className="gallery-card bg-bg-parchment flex flex-col items-center justify-center p-10 group cursor-pointer border-dashed border-2 border-border-rich">
        <div className="w-16 h-16 rounded-full border border-border-rich flex items-center justify-center mb-6 group-hover:bg-accent-gold group-hover:text-white transition-all">
         <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M5 12h14M12 5l7 7-7 7" /></svg>
        </div>
        <h3 className="text-[13px] font-heading font-bold text-fg-main uppercase tracking-widest text-center">Load Seasonals</h3>
       </div>
      </div>
     </section>

     {/* Editorial Footer */}
     <footer className="px-12 py-32 bg-bg-parchment border-t border-border-light">
      <div className="max-w-[1440px] mx-auto grid grid-cols-1 md:grid-cols-4 gap-20">
       <div className="col-span-1 md:col-span-2">
        <div className="brand-title text-accent-gold mb-6">Пекарня Смысл Есть</div>
        <h4 className="text-[32px] font-heading font-bold leading-tight mb-8">
         CRAFTED FOR THOSE WHO <br />APPRECIATE THE ART OF THE CRUST.
        </h4>
        <p className="text-[15px] text-fg-soft leading-relaxed max-w-[400px]">
         Our bakery operates on three principles: Respect for grain, long fermentation, and the joy of shared bread.
        </p>
       </div>
       <div>
        <h5 className="text-[11px] font-black uppercase tracking-[0.2em] mb-10 text-fg-muted">Our Studio</h5>
        <ul className="space-y-6 text-[13px] font-bold text-fg-main uppercase tracking-widest">
         <li className="hover:text-accent-gold cursor-pointer transition-colors">About Us</li>
         <li className="hover:text-accent-gold cursor-pointer transition-colors">Sustainability</li>
         <li className="hover:text-accent-gold cursor-pointer transition-colors">Wholesale</li>
        </ul>
       </div>
       <div>
        <h5 className="text-[11px] font-black uppercase tracking-[0.2em] mb-10 text-fg-muted">Reach out</h5>
        <ul className="space-y-6 text-[13px] font-bold text-fg-main uppercase tracking-widest">
         <li className="hover:text-accent-gold cursor-pointer transition-colors">Instagram</li>
         <li className="hover:text-accent-gold cursor-pointer transition-colors">Press Inquiries</li>
         <li className="hover:text-accent-gold cursor-pointer transition-colors">Contact</li>
        </ul>
       </div>
      </div>
     </footer>
    </div>

    {/* Boutique Cart Interface (Desktop) */}
    <div className="hidden lg:block w-[400px] xl:w-[460px] h-screen sticky top-0 flex-shrink-0 z-50">
     <CartSidebar cart={cart} onUpdateQuantity={updateQty} total={total} />
    </div>
   </main>
  </div>
 );
}
